/**
 * MedX shadows theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Elevation shadows for cards and overlays.
 */
const SHADOWS_TOKENS = Object.freeze({
  primary: { value: "theme-shadows-primary", scope: "theme" },
  secondary: { value: "theme-shadows-secondary", scope: "theme" },
  muted: { value: "theme-shadows-muted", scope: "theme" },
  accent: { value: "theme-shadows-accent", scope: "theme" },
  surface: { value: "theme-shadows-surface", scope: "theme" },
});

const SHADOWS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SHADOWS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const shadowsRegistry = new Map();
const SHADOWS_listeners = new Set();
let SHADOWS_seq = 0;

function createShadowsId(prefix = "medx-theme-shadows") {
  SHADOWS_seq += 1;
  return `${prefix}-${SHADOWS_seq}`;
}

function registerShadows(config = {}) {
  const entryId = config.id ?? createShadowsId();
  const preset = SHADOWS_PRESETS[config.preset ?? "default"] ?? SHADOWS_PRESETS.default;
  const token = SHADOWS_TOKENS[config.token ?? preset.token] ?? SHADOWS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SHADOWS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  shadowsRegistry.set(entryId, entry);
  notifyShadowsListeners("register", entry);
  return entry;
}

function updateShadows(id, patch = {}) {
  const entry = shadowsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyShadowsListeners("update", entry);
  return entry;
}

function resolveShadows(id) {
  const entry = shadowsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listShadowsEntries(filter = {}) {
  let items = Array.from(shadowsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onShadowsEvent(listener) {
  SHADOWS_listeners.add(listener);
  return () => SHADOWS_listeners.delete(listener);
}

function notifyShadowsListeners(type, entry) {
  for (const listener of SHADOWS_listeners) {
    try {
      listener({ type, entry, registrySize: shadowsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:shadows] listener error", err.message);
    }
  }
}

function getShadowsMetrics() {
  const items = listShadowsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SHADOWS_TOKENS).length,
    presets: Object.keys(SHADOWS_PRESETS).length,
  };
}

async function runMedxShadows() {
  console.log("[medx:ui:theme:shadows] runtime initialized");
  console.log(`[medx:ui:theme:shadows] tokens=${Object.keys(SHADOWS_TOKENS).length} presets=${Object.keys(SHADOWS_PRESETS).length}`);

  const events = [];
  onShadowsEvent((e) => events.push(e.type));

  const domains = Object.keys(SHADOWS_SUPPLY_CHAIN);
  const presets = Object.keys(SHADOWS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerShadows({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/shadows" },
    });
  }

  const first = listShadowsEntries()[0];
  if (first) updateShadows(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getShadowsMetrics();
  const resolved = first ? resolveShadows(first.id) : null;

  console.log(`[medx:ui:theme:shadows] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:shadows] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:shadows] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:shadows] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:shadows] bootstrap complete");
}

module.exports = runMedxShadows;
